const issue = $input.item.json.body.issue;
const repo = $input.item.json.body.repository;
const title = (issue.title || '').toLowerCase();
const body = (issue.body || '').toLowerCase();
const combined = title + ' ' + body;

// ── Category detection ────────────────────────────────────────────
const CATEGORIES = [
  { name: 'bug', keywords: ['bug', 'error', 'crash', 'broken', 'fail', 'exception', 'traceback', 'not working', 'doesn\'t work', 'wrong', 'incorrect'], label: 'bug', emoji: '🐛' },
  { name: 'feature', keywords: ['feature', 'request', 'add', 'would be nice', 'could you', 'please add', 'support for', 'allow', 'enable', 'implement'], label: 'enhancement', emoji: '✨' },
  { name: 'performance', keywords: ['slow', 'performance', 'memory', 'leak', 'lag', 'timeout', 'speed', 'optimize', 'cpu', 'ram'], label: 'performance', emoji: '⚡' },
  { name: 'security', keywords: ['security', 'vulnerability', 'cve', 'exploit', 'injection', 'xss', 'csrf', 'auth bypass', 'privilege'], label: 'security', emoji: '🔐' },
  { name: 'docs', keywords: ['documentation', 'docs', 'readme', 'typo', 'unclear', 'missing doc', 'example'], label: 'documentation', emoji: '📚' },
  { name: 'question', keywords: ['how to', 'how do i', 'question', 'help', 'confused', 'understand', '?'], label: 'question', emoji: '❓' }
];

let category = { name: 'general', label: 'needs-triage', emoji: '📋' };
let matchScore = 0;
for (const cat of CATEGORIES) {
  const hits = cat.keywords.filter(k => combined.includes(k)).length;
  if (hits > matchScore) { matchScore = hits; category = cat; }
}

// ── Priority scoring ──────────────────────────────────────────────
let priorityScore = 0;
const PRIORITY_SIGNALS = [
  { pattern: /crash|critical|urgent|production|down|outage|broken in prod/i, points: 40 },
  { pattern: /security|vulnerability|exploit/i, points: 35 },
  { pattern: /data loss|corrupt/i, points: 30 },
  { pattern: /error|exception|fail/i, points: 10 },
  { pattern: /performance|slow|memory leak/i, points: 8 },
  { pattern: /\bsteps to reproduce\b|reproducible/i, points: 5 },
  { pattern: /expected.*actual|actual.*expected/i, points: 5 }
];
for (const sig of PRIORITY_SIGNALS) {
  if (sig.pattern.test(combined)) priorityScore += sig.points;
}

const priority = priorityScore >= 40 ? { level: 'CRITICAL', label: 'priority-critical', emoji: '🔴', days: 1 }
               : priorityScore >= 20 ? { level: 'HIGH',     label: 'priority-high',     emoji: '🟠', days: 3 }
               : priorityScore >= 10 ? { level: 'MEDIUM',   label: 'priority-medium',   emoji: '🟡', days: 7 }
               :                       { level: 'LOW',      label: 'priority-low',      emoji: '🟢', days: 14 };

// ── Auto-assignment logic ─────────────────────────────────────────
const OWNER_MAP = {
  bug: 'YOUR_BUG_TRIAGE_USER',
  feature: 'YOUR_PM_USER',
  performance: 'YOUR_PERF_USER',
  security: 'YOUR_SECURITY_USER',
  docs: 'YOUR_DOCS_USER',
  question: 'YOUR_SUPPORT_USER',
  general: 'YOUR_DEFAULT_USER'
};
const assignee = OWNER_MAP[category.name] || OWNER_MAP.general;

// ── SLA due date ─────────────────────────────────────────────────
const dueDate = new Date();
dueDate.setDate(dueDate.getDate() + priority.days);
const dueDateStr = dueDate.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' });

const labelsToAdd = [category.label, priority.label];
const commentBody = `## ${category.emoji} Automated Triage Report\n\n| Field | Value |\n|---|---|\n| **Category** | ${category.emoji} ${category.name} |\n| **Priority** | ${priority.emoji} ${priority.level} (score: ${priorityScore}) |\n| **Assigned to** | @${assignee} |\n| **SLA Due** | ${dueDateStr} (${priority.days} day${priority.days > 1 ? 's' : ''}) |\n\n### What happens next\n- This issue has been labelled and assigned automatically\n- ${priority.level === 'CRITICAL' ? '🚨 **CRITICAL**: Team has been alerted immediately' : `Expected response within ${priority.days} day${priority.days > 1 ? 's' : ''}`}\n- If this categorization is wrong, please relabel manually\n\n---\n*Triaged automatically by n8n workflow*`;

return [{
  json: {
    issue_number: issue.number,
    issue_title: issue.title,
    issue_url: issue.html_url,
    issue_body_short: issue.body ? issue.body.substring(0, 300) : 'No description.',
    author: issue.user.login,
    author_url: issue.user.html_url,
    repo: repo.full_name,
    category_name: category.name,
    category_label: category.label,
    category_emoji: category.emoji,
    priority_level: priority.level,
    priority_label: priority.label,
    priority_emoji: priority.emoji,
    priority_score: priorityScore,
    priority_days: priority.days,
    sla_due: dueDateStr,
    assignee: assignee,
    labels_to_add: labelsToAdd,
    comment_body: commentBody,
    created_at: new Date(issue.created_at).toLocaleString(),
    is_critical: priorityScore >= 40
  }
}];

